mapper.select:
SELECT id, action, entity_type, entity_id, user_id, old_value, new_value, ip_address, status, message, created_at FROM audit_logs
action LIKE CONCAT('%', #{action}, '%')
AND entity_type = #{entityType}
AND user_id = #{userId}
AND ip_address LIKE CONCAT('%', #{ipAddress}, '%')
ORDER BY created_at DESC, id DESC LIMIT 500
